import { useTheme } from '@/theme/ThemeContext';

export function RoomsList({ onRoomSelect }: RoomsListProps) {
  const { scale } = useTheme();

  const rooms: RoomConfig[] = [
    {
      id: "library",
      title: "Quiet Library",
      peopleCount: 42,
      gradient: ['#C8A882', '#A07850'],
      iconBg: '#E8D5BF',
      textColor: '#3D2010',
      subtitleColor: '#6B4C3E',
      icon: <Ionicons name="book" size={22 * scale} color="#3D2010" />,
      vector: <LibraryVector />,
    },
    {
      id: "cafe",
      title: "Busy Cafe",
      peopleCount: 100,
      gradient: ['#C0C6F5', '#9BA3E8'],
      iconBg: '#DCDFF8',
      textColor: '#1E2A6E',
      subtitleColor: '#4050A0',
      icon: <Ionicons name="cafe" size={22 * scale} color="#1E2A6E" />,
      vector: <CafeVector />,
    },
    {
      id: "study",
      title: "Study Hall",
      peopleCount: 20,
      gradient: ['#F5DFA0', '#ECC850'],
      iconBg: '#FFF3D0',
      textColor: '#6B4A00',
      subtitleColor: '#9A7520',
      icon: <Ionicons name="school" size={22 * scale} color="#6B4A00" />,
      vector: <StudyVector />,
    },
    {
      id: "park",
      title: "Relaxing Park",
      peopleCount: 67,
      gradient: ['#A8CCBF', '#78B0A0'],
      iconBg: '#D0E8E0',
      textColor: '#1A3D30',
      subtitleColor: '#3A6858',
      icon: <MaterialCommunityIcons name="tree" size={22 * scale} color="#1A3D30" />,
      vector: <ParkVector />,
    }
  ];

  return (
    <View style={styles.list}>
      {rooms.map((room) => {
        return (
          <TouchableOpacity
            key={room.id}
            style={styles.card}
            onPress={() => onRoomSelect?.(room.id)}
            activeOpacity={0.9}
          >
            <LinearGradient 
              colors={room.gradient} 
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 1 }}
              style={StyleSheet.absoluteFillObject}
            />
            
            {/* Decorative vector */}
            {room.vector}

            <View style={[styles.iconContainer, { width: 44 * scale, height: 44 * scale, borderRadius: 22 * scale, backgroundColor: room.iconBg }]}>
              {room.icon}
            </View>

            <View style={styles.textContainer}>
              <Text style={[styles.title, { color: room.textColor, fontSize: 22 * scale, lineHeight: 28 * scale }]}>
                {room.title}
              </Text>
              <Text style={[styles.subtitle, { color: room.subtitleColor, fontSize: 14 * scale }]}>
                {room.peopleCount} people
              </Text>
            </View>
          </TouchableOpacity>
        );
      })}
    </View>
  );
}

const styles = StyleSheet.create({
  list: { 
    gap: 20,
    marginTop: 8,
  },
  card: {
    height: 148,
    borderRadius: 24,
    padding: 20,
    justifyContent: 'space-between',
    overflow: 'hidden',
    position: 'relative',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.08,
    shadowRadius: 12,
    elevation: 3,
  },
  iconContainer: {
    width: 44,
    height: 44,
    borderRadius: 22,
    alignItems: 'center',
    justifyContent: 'center',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.06,
    shadowRadius: 4,
    elevation: 1,
    zIndex: 2,
  },
  textContainer: {
    zIndex: 2,
  },
  title: { 
    fontFamily: 'SourceSerifPro-Bold', 
    fontSize: 22, 
    lineHeight: 28,
  },
  subtitle: { 
    fontFamily: 'Poppins-Regular', 
    fontSize: 14, 
    marginTop: 2,
  },
});

export default RoomsList;
